mkdir -p logs/iter_${RAB_ITERATION} && python - <<'PY'
import os, json, importlib.util, itertools
from collections import Counter, defaultdict
out={}
for fn in ['model.py','predict.py','train.py','val_eval.py','probe_qwen.py']:
    try:
        with open(fn,'r') as f: out[fn]=f.read()
    except Exception as e: out[fn]=str(e)
# package availability
mods=['peft','trl','bitsandbytes','qwen_vl_utils','transformers','accelerate']
out['modules']={m: importlib.util.find_spec(m) is not None for m in mods}
# data stats and examples
for split in ['unified_train.jsonl','unified_val.jsonl']:
    path=os.path.join('/data',split)
    stats={'n':0,'has_bbox':0,'has_point':0,'types':Counter(),'sources':Counter(),'w':Counter(),'h':Counter(),'examples':[]}
    if os.path.exists(path):
        with open(path) as f:
            for line in f:
                r=json.loads(line); stats['n']+=1
                stats['has_bbox']+=int('target_bbox' in r and r['target_bbox'] is not None)
                stats['has_point']+=int('target_point' in r and r['target_point'] is not None)
                stats['types'][r.get('type','')]+=1; stats['sources'][r.get('source','')]+=1
                stats['w'][r.get('image_width')]+=1; stats['h'][r.get('image_height')]+=1
                if len(stats['examples'])<5: stats['examples'].append(r)
    stats['types']=dict(stats['types']); stats['sources']=dict(stats['sources'])
    stats['top_w']=stats['w'].most_common(10); stats['top_h']=stats['h'].most_common(10)
    del stats['w']; del stats['h']
    out[split]=stats
# checkpoint metadata
for ck in ['checkpoints/baseline','checkpoints/qwen_base']:
    meta=os.path.join(ck,'meta.json')
    out[ck]={'exists':os.path.exists(ck),'meta':None,'files':[]}
    if os.path.exists(meta):
        try: out[ck]['meta']=json.load(open(meta))
        except Exception as e: out[ck]['meta']=str(e)
    if os.path.exists(ck):
        for root, dirs, files in os.walk(ck):
            if len(out[ck]['files'])<30:
                for name in files[:5]: out[ck]['files'].append(os.path.relpath(os.path.join(root,name),ck))
# recent val eval lines
for lf in ['logs/val_eval_qwen_base.jsonl','logs/val_eval_rescaled.jsonl','logs/probe_qwen_rescaled.jsonl','logs/probe_qwen.jsonl']:
    if os.path.exists(lf):
        lines=open(lf).read().splitlines()
        out[lf]={'nlines':len(lines),'head':lines[:3],'tail':lines[-3:]}
with open(f"logs/iter_{os.environ.get('RAB_ITERATION','x')}/inspect.json",'w') as f: json.dump(out,f,indent=2,default=str)
print(json.dumps({'written':f"logs/iter_{os.environ.get('RAB_ITERATION','x')}/inspect.json",'modules':out['modules'],'train_n':out['unified_train.jsonl']['n'],'val_n':out['unified_val.jsonl']['n'],'train_bbox':out['unified_train.jsonl']['has_bbox'],'train_point':out['unified_train.jsonl']['has_point']},default=str))
